CREATE TABLE cd_products(id SERIAL PRIMARY KEY, name TEXT NOT NULL, term_months INT NOT NULL, rate_bps INT NOT NULL, penalty_bps INT NOT NULL, min_deposit_cents BIGINT NOT NULL);
CREATE TABLE accounts(id SERIAL PRIMARY KEY, member_name TEXT NOT NULL, wallet_address TEXT NOT NULL, did TEXT NOT NULL, kind TEXT NOT NULL CHECK (kind IN ('checking','cd_funding')), created_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE transactions(id SERIAL PRIMARY KEY, account_id INT REFERENCES accounts NOT NULL, amount_cents BIGINT NOT NULL, kind TEXT NOT NULL CHECK (kind IN ('deposit','withdrawal')), product_id INT REFERENCES cd_products NULL, memo TEXT, attested BOOLEAN DEFAULT false, created_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE attestations(id SERIAL PRIMARY KEY, transaction_id INT UNIQUE REFERENCES transactions NOT NULL, deposit_id TEXT NOT NULL, payload JSONB NOT NULL, signed_at TIMESTAMPTZ DEFAULT now());
